function CurrencyConverter() {
  const [amount, setAmount] = React.useState(100);
  const [from, setFrom] = React.useState('REPLACE_WITH_FROM_CURRENCY');
  const [to, setTo] = React.useState('REPLACE_WITH_TO_CURRENCY');
  const [rate, setRate] = React.useState(null);
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    if (!from || !to) return;
    setLoading(true);
    fetch(`https://api.exchangerate-api.com/v4/latest/${from}`)
      .then(r=>r.json())
      .then(d=>{setRate(d.rates?.[to]);setLoading(false);})
      .catch(()=>setLoading(false));
  }, [from,to]);

  const result = rate ? (amount * rate).toFixed(2) : '---';
  const currencies = ['USD','EUR','GBP','JPY','AUD','CAD','CHF','CNY','SEK','NZD'];

  return (
    <div style={{padding:20,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',justifyContent:'center'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:16,textAlign:'center'}}>Currency Converter</div>
      <div style={{display:'flex',gap:8,alignItems:'center',marginBottom:16}}>
        <input type="number" value={amount} onChange={e=>setAmount(Number(e.target.value))}
          style={{flex:1,padding:'10px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:16}}/>
        <select value={from} onChange={e=>setFrom(e.target.value)}
          style={{padding:'10px',borderRadius:8,border:'1px solid #ccc',fontSize:16}}>
          {currencies.map(c=><option key={c} value={c}>{c}</option>)}
        </select>
      </div>
      <div style={{textAlign:'center',fontSize:24,margin:'8px 0'}}>↓</div>
      <div style={{display:'flex',gap:8,alignItems:'center',marginBottom:16}}>
        <div style={{flex:1,padding:'10px 12px',borderRadius:8,background:'#f5f5f5',fontSize:16,fontWeight:600}}>
          {loading?'Loading…':result}
        </div>
        <select value={to} onChange={e=>setTo(e.target.value)}
          style={{padding:'10px',borderRadius:8,border:'1px solid #ccc',fontSize:16}}>
          {currencies.map(c=><option key={c} value={c}>{c}</option>)}
        </select>
      </div>
      {rate && <div style={{textAlign:'center',fontSize:13,color:'#888'}}>
        1 {from} = {rate.toFixed(4)} {to}
      </div>}
    </div>
  );
}
render(<CurrencyConverter/>);
